เพิ่ม while loop ให้ Chatbot คุยได้ต่อเนื่อง:

```python
def ai_chat(question):
    q = question.lower()
    if "สวัสดี" in q:
        return "สวัสดี! 🤖 มีอะไรให้ช่วยไหม?"
    elif "ชื่อ" in q:
        return "ฉันชื่อ ACA-Bot!"
    elif "กี่โมง" in q:
        return "ฉันไม่รู้เวลา แต่ตอนนี้เป็นเวลาแห่งการเรียนรู้! 📚"
    elif "ลาก่อน" in q or "bye" in q:
        return "ลาก่อน! แล้วพบกันใหม่ 👋"
    else:
        return f'ขอโทษ ฉันไม่รู้เรื่อง "{question}" 🤔'

# Main loop
print("=== ACA-Bot เริ่มทำงาน ===")
while True:
    user_input = input("คุณ: ")
    if user_input == "ลาก่อน":
        print("Bot: ลาก่อน! แล้วพบกันใหม่ 👋")
        break
    response = ai_chat(user_input)
    print(f"Bot: {response}")
```

